import { priorityQueue } from 'typescript-collections';

function solve(n, edges) {
  // Build the graph
  const graph = {};
  for (let i = 0; i < n; i++) {
    graph[i] = [];
  }
  for (const [u, v, w] of edges) {
    graph[u].push([v, w]);
  }

  // Dijkstra's algorithm with state tracking (node, switch_used)
  // Each state is (cost, node, switch_used)
  const pq = new priorityQueue((a, b) => a[0] - b[0]);
  pq.enqueue([0, 0, false]);

  // visited: Map of node to Map of switch_used to cost
  const visited = new Map();
  visited.set(0, new Map([[false, 0]]));

  while (!pq.isEmpty()) {
    const [cost, node, switchUsed] = pq.dequeue();
    if (node === n - 1) {
      return cost;
    }

    // If we've already found a better path to this state, skip
    const nodeMap = visited.get(node);
    if (nodeMap.has(switchUsed) && nodeMap.get(switchUsed) <= cost) {
      continue;
    }

    // Explore neighbors
    for (const [v, w] of graph[node]) {
      // Regular edge
      const newCost = cost + w;
      if (!visited.has(v) || visited.get(v).has(false) && visited.get(v).get(false) > newCost) {
        visited.set(v, new Map([[false, newCost]]));
        pq.enqueue([newCost, v, false]);
      } else if (visited.get(v).has(false) && visited.get(v).get(false) > newCost) {
        visited.get(v).set(false, newCost);
        pq.enqueue([newCost, v, false]);
      }

      // Reverse edge (if switch hasn't been used)
      if (!switchUsed) {
        const newCostRev = cost + 2 * w;
        if (!visited.has(v) || visited.get(v).has(true) && visited.get(v).get(true) > newCostRev) {
          visited.set(v, new Map([[true, newCostRev]]));
          pq.enqueue([newCostRev, v, true]);
        } else if (visited.get(v).has(true) && visited.get(v).get(true) > newCostRev) {
          visited.get(v).set(true, newCostRev);
          pq.enqueue([newCostRev, v, true]);
        }
      }
    }
  }

  return -1;
}
